\tzpsection{Derivation Layer}
\paragraph{Primary Equation.}
\begin{equation}
\frac{P(H_i\mid D)}
{P(H_j\mid D)}
=
\frac{P(D\mid H_i)}
{P(D\mid H_j)}
\frac{P(H_i)}
{P(H_j)} .
\end{equation}

\paragraph{Primary Derivation.}
Bayes' rule gives the posterior probability of a hypothesis $H_i$ after observing data $D$:

\begin{equation}
P(H_i\mid D)
=
\frac{P(D\mid H_i)P(H_i)}
{P(D)} .
\end{equation}

Likewise,

\begin{equation}
P(H_j\mid D)
=
\frac{P(D\mid H_j)P(H_j)}
{P(D)} .
\end{equation}

Taking the ratio cancels the evidence denominator $P(D)$:

\begin{equation}
\frac{P(H_i\mid D)}
{P(H_j\mid D)}
=
\frac{P(D\mid H_i)P(H_i)}
{P(D\mid H_j)P(H_j)} .
\end{equation}

Rearranging gives:

\begin{equation}
\boxed{
\frac{P(H_i\mid D)}
{P(H_j\mid D)}
=
\frac{P(D\mid H_i)}
{P(D\mid H_j)}
\frac{P(H_i)}
{P(H_j)} .
}
\end{equation}

\paragraph{Interpretation.}
This equation formalizes evidence accumulation: posterior odds equal likelihood ratio times prior odds.
% END TZP DERIVATION LAYER
